const now = new Date();
// Calculate this week's Monday
const dayOfWeek = now.getDay();
const mondayOffset = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;
const monday = new Date(now);
monday.setDate(now.getDate() + mondayOffset);
monday.setHours(0, 0, 0, 0);

const fridayDate = now.toISOString().split('T')[0];
const mondayDate = monday.toISOString().split('T')[0];
const weekNumber = Math.ceil((now - new Date(now.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000));

return [{ json: { weekStart: mondayDate, weekEnd: fridayDate, weekNumber } }];

const logs = $('Fetch Week Activity Logs').all().map(i => i.json);
const vulns = $('Fetch Week Vulnerabilities').all().map(i => i.json);
const tasks = $('Fetch All Tasks').all().map(i => i.json);
const weekData = $('Calculate Week Range').first().json;

function getProp(props, key, type) {
  const p = props?.[key];
  if (!p) return null;
  if (type === 'title') return p.title?.[0]?.plain_text || null;
  if (type === 'text') return p.rich_text?.[0]?.plain_text || null;
  if (type === 'select') return p.select?.name || null;
  if (type === 'number') return p.number || 0;
  if (type === 'date') return p.date?.start || null;
  if (type === 'relation') return (p.relation || []).map(r => r.id);
  return null;
}

// Aggregate logs by pentester
const logsByPentester = {};
let totalHours = 0;
logs.forEach(log => {
  const pentesterRel = getProp(log.properties, 'pentester_id', 'relation') || [];
  const pentesterId = pentesterRel[0] || 'unknown';
  const hours = getProp(log.properties, 'hours_spent', 'number');
  const activity = getProp(log.properties, 'activity_description', 'text') || '';
  const date = getProp(log.properties, 'log_date', 'date');
  totalHours += hours;
  if (!logsByPentester[pentesterId]) logsByPentester[pentesterId] = { logs: [], totalHours: 0 };
  logsByPentester[pentesterId].logs.push({ date, activity: activity.substring(0, 100), hours });
  logsByPentester[pentesterId].totalHours += hours;
});

// Vulnerability stats
const vulnStats = {
  total: vulns.length,
  by_severity: {},
  details: []
};
vulns.forEach(v => {
  const sev = getProp(v.properties, 'severity', 'select') || 'Unknown';
  vulnStats.by_severity[sev] = (vulnStats.by_severity[sev] || 0) + 1;
  vulnStats.details.push({
    name: getProp(v.properties, 'vulnerability_name', 'text'),
    severity: sev,
    cvss: getProp(v.properties, 'cvss_score', 'number'),
    target: getProp(v.properties, 'affected_target', 'text')
  });
});

// Task completion stats
const taskStats = {
  total: tasks.length,
  done: tasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Done').length,
  in_progress: tasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'In Progress').length,
  blocked: tasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Blocked').length,
  not_started: tasks.filter(t => getProp(t.properties, 'task_status', 'select') === 'Not Started').length
};

const blockedTasks = tasks
  .filter(t => getProp(t.properties, 'task_status', 'select') === 'Blocked')
  .map(t => ({
    name: getProp(t.properties, 'task_name', 'text'),
    reason: getProp(t.properties, 'blocking_reason', 'text')
  }));

return [{ json: {
  weekData,
  logsByPentester,
  totalHours,
  totalLogs: logs.length,
  vulnStats,
  taskStats,
  blockedTasks
} }];

const recapText = $input.first().json.text || 'Weekly recap tidak dapat dibuat.';
const weekData = $('Calculate Week Range').first().json;
return [{ json: { recapText, weekNum: weekData.weekNumber, weekStart: weekData.weekStart, weekEnd: weekData.weekEnd, chatId: $vars.PENTESTER_GROUP_CHAT_ID } }];
